#include <stdio.h>
const int INF = 1e9;
int min(int a, int b) { return (a < b) ? a : b; }
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int dp[n + 1][n + 1];
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if(i == j) dp[i][j] = 0;
            else dp[i][j] = INF;
        }
    }
    for (int i = 0; i < m; i++) {
        int u, v, w;
        scanf("%d %d %d", &u, &v, &w);
        dp[u][v] = w;
        dp[v][u] = w;
    }
    for (int k = 1; k <= n; k++) {
        for (int u = 1; u <= n; u++) {
            for (int v = 1; v <= n; v++) {
                dp[u][v] = min(dp[u][v], dp[u][k] + dp[k][v]);
            }
        }
    }
    for (int u = 1; u <= n; u++) {
        for (int v = 1; v <= n; v++) {
            if (dp[u][v] == INF) {
                printf("-1 ");
            } else {
                printf("%d ", dp[u][v]);
            }
        }
        printf("\n");
    }
    return 0;
}

