const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const INF = 10**9;
const readline = () => lines[idx++];
const [n, m] = readline().split(' ').map(Number);
const dp = Array(n + 1).fill().map(() => Array(n + 1).fill(INF));
for(let i = 1; i <= n; i++) dp[i][i] = 0;
for (let i = 0; i < m; i++) {
    const [u, v, w] = readline().split(' ').map(Number);
    dp[u][v] = w;
    dp[v][u] = w;
}
for (let k = 1; k <= n; k++) {
    for (let u = 1; u <= n; u++) {
        for (let v = 1; v <= n; v++) {
            dp[u][v] = Math.min(dp[u][v], dp[u][k] + dp[k][v]);
        }
    }
}
for (let u = 1; u <= n; u++) {
    let row = '';
    for (let v = 1; v <= n; v++) {
        if (dp[u][v] === INF) {
            row += '-1 ';
        } else {
            row += dp[u][v] + ' ';
        }
    }
